# Auto-generated by tdd_orchestrator.py — Stage: affine
# Manually fixed template issues
"""
TDD Stage: affine
Reader adds gamma/beta stick reads. Compute adds gamma/beta tilize, mul<ROW>(gamma),
add<ROW>(beta). Full layer normalization with affine transform.
"""

import pytest
import torch
import torch.nn.functional
import ttnn

from .layer_norm_rm import layer_norm_rm


def pytorch_reference(x, gamma_tensor, beta_tensor):
    """PyTorch reference for this stage."""
    return torch.nn.functional.layer_norm(
        x, [x.shape[-1]], weight=gamma_tensor.squeeze(), bias=beta_tensor.squeeze(), eps=1e-5
    )


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_affine(device, shape):
    """Verify full layer normalization with affine transform."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma_tensor = torch.randn(1, 1, 1, shape[-1])
    beta_tensor = torch.randn(1, 1, 1, shape[-1])

    expected = pytorch_reference(torch_input, gamma_tensor, beta_tensor)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_ttnn = ttnn.from_torch(
        gamma_tensor,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    beta_ttnn = ttnn.from_torch(
        beta_tensor,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm_rm(ttnn_input, gamma_ttnn, beta_ttnn)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
